@use '../../styles/tokens' as *;

.command-palette-overlay {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: flex-start;
  justify-content: center;
  padding-top: 15vh;
}

.command-palette {
  position: relative;
  width: 750px;
  max-width: calc(100vw - $space-6 * 2);
  max-height: 500px;
  display: flex;
  flex-direction: column;
  background-color: rgba($color-surface, 0.78);
  backdrop-filter: blur(64px) saturate(200%);
  -webkit-backdrop-filter: blur(64px) saturate(200%);
  border-radius: $radius-xl;
  border: 1px solid rgba(255, 255, 255, 0.08);
  box-shadow: $shadow-window;
  overflow: hidden;
  animation: palette-appear $transition-slow ease-out both;
}

.command-palette__body {
  display: flex;
  flex: 1;
  min-height: 0;
  overflow: hidden;
}

.command-palette__list-container {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-width: 0;
  overflow: hidden;

  .command-palette__body--has-detail & {
    flex: 0 0 40%;
  }
}

