@use '../../styles/tokens' as *;

.search-bar {
  display: flex;
  align-items: center;
  height: $search-bar-height;
  padding: 0 $space-4;
  border-bottom: 1px solid $color-border;
  gap: $space-3;
}

.search-bar__icon {
  flex-shrink: 0;
  color: $color-text-tertiary;
}

.search-bar__breadcrumbs {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  gap: $space-half;
